<?php
 namespace League\CommonMark\Extension\TableOfContents\Normalizer; use League\CommonMark\Block\Element\ListBlock; use League\CommonMark\Block\Element\ListItem; use League\CommonMark\Extension\TableOfContents\Node\TableOfContents; final class AsIsNormalizerStrategy implements NormalizerStrategyInterface { private $parentListBlock; private $parentLevel = 1; private $lastListItem; public function __construct(TableOfContents $toc) { $this->parentListBlock = $toc; } public function addItem(int $level, ListItem $listItemToAdd): void { while ($level > $this->parentLevel) { if ($this->lastListItem === null) { $this->lastListItem = new ListItem($this->parentListBlock->getListData()); $this->parentListBlock->appendChild($this->lastListItem); } $newListBlock = new ListBlock($this->parentListBlock->getListData()); $newListBlock->setStartLine($listItemToAdd->getStartLine()); $newListBlock->setEndLine($listItemToAdd->getEndLine()); $this->lastListItem->appendChild($newListBlock); $this->parentListBlock = $newListBlock; $this->lastListItem = null; $this->parentLevel++; } while ($level < $this->parentLevel) { while (true) { $this->parentListBlock = $this->parentListBlock->parent(); if ($this->parentListBlock instanceof ListBlock) { break; } } $this->parentLevel--; } $this->parentListBlock->appendChild($listItemToAdd); $this->lastListItem = $listItemToAdd; } } \class_exists(TableOfContents::class); 